<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;height:100vh;}
  #controls{margin-top:10px;}
  button{background:#444;border:none;padding:8px 12px;margin:0 4px;color:#fff;border-radius:4px;cursor:pointer;}
  button:hover{background:#555;}
  canvas#life{border:2px solid #555;background:#111;}
</style>
</head>
<body>
<canvas id="life" width="400" height="400"></canvas>
<div id="controls">
  <button id="step">Step</button>
  <button id="play">Play</button>
  <button id="random">Random</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const w = 40, h = 40; // grid dimensions
  const cellSize = canvas.width / w;
  let cells = new Uint8Array(w*h);
  let running = false, timer;

  function idx(x,y){return y*w+x;}
  function get(x,y){ return (x<0||y<0||x>=w||y>=h)?0:cells[idx(x,y)]; }
  function set(x,y,v){ if(x>=0&&y>=0&&x<w&&y<h) cells[idx(x,y)] = v?1:0; }

  function draw(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        if(cells[idx(x,y)]) {
          ctx.fillStyle='#fff';
          ctx.fillRect(x*cellSize+1,y*cellSize+1,cellSize-2,cellSize-2);
        }
      }
    }
  }

  function step(){
    const next = new Uint8Array(w*h);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        let liveNeighbors=0;
        for(let dy=-1;dy<=1;dy++)for(let dx=-1;dx<=1;dx++){
          if(dx||dy) liveNeighbors+=get(x+dx,y+dy);
        }
        const cur = get(x,y);
        next[idx(x,y)] = (cur && (liveNeighbors===2 || liveNeighbors===3)) ||
                         (!cur && liveNeighbors===3) ? 1 : 0;
      }
    }
    cells = next;
    draw();
  }

  function clearGrid(){ cells.fill(0); draw(); }

  function randomize(){
    for(let i=0;i<cells.length;i++) cells[i] = Math.random()<0.2?1:0;
    draw();
  }

  // API
  window.life = { w, h, get, set, step, clear:clearGrid };

  // Controls
  document.getElementById('step').onclick=step;
  document.getElementById('play').onclick=function(){
    if(running){ running=false; this.textContent='Play'; clearInterval(timer); }
    else{ running=true; this.textContent='Pause'; timer=setInterval(step,200); }
  };
  document.getElementById('random').onclick=randomize;
  document.getElementById('clear').onclick=clearGrid;

  // Mouse interaction
  let drawing=false;
  canvas.addEventListener('mousedown',e=>{
    drawing=true; toggleCell(e);
  });
  canvas.addEventListener('mousemove',e=>{ if(drawing) toggleCell(e); });
  canvas.addEventListener('mouseup',()=>drawing=false);
  canvas.addEventListener('mouseleave',()=>drawing=false);

  function toggleCell(e){
    const rect=canvas.getBoundingClientRect();
    const x=Math.floor((e.clientX-rect.left)/cellSize);
    const y=Math.floor((e.clientY-rect.top)/cellSize);
    set(x,y, !get(x,y));
    draw();
  }

  // Initial draw
  draw();
})();
</script>
</body>
</html>
